import React, { useState } from 'react';
import './App.css';

const gridSize = 8;

const baseCharacters = [
  { name: 'Knight', hp: 100, atk: 30, sprite: '/sprites/knight.png' },
  { name: 'Archer', hp: 80, atk: 25, sprite: '/sprites/archer.png' },
  { name: 'Mage', hp: 70, atk: 40, sprite: '/sprites/mage.png' },
  { name: 'Healer', hp: 90, atk: 10, sprite: '/sprites/healer.png' },
  { name: 'Warrior', hp: 110, atk: 35, sprite: '/sprites/warrior.png' },
  { name: 'Rogue', hp: 75, atk: 30, sprite: '/sprites/rogue.png' },
  { name: 'Summoner', hp: 65, atk: 45, sprite: '/sprites/summoner.png' },
  { name: 'Paladin', hp: 95, atk: 20, sprite: '/sprites/paladin.png' },
];

let idCounter = 1;
const generateTeam = (team, row) =>
  baseCharacters.map((c, i) => ({
    ...c,
    id: idCounter++,
    x: i,
    y: row,
    team,
  }));

const initialCharacters = [...generateTeam('A', 0), ...generateTeam('B', gridSize - 1)];

function App() {
  const [characters, setCharacters] = useState(initialCharacters);
  const [selectedId, setSelectedId] = useState(null);
  const [turn, setTurn] = useState('A');

  const selectedChar = characters.find(c => c.id === selectedId);

  const moveCharacter = (id, dx, dy) => {
    setCharacters(prev =>
      prev.map(c => {
        if (c.id === id && c.team === turn) {
          const newX = Math.max(0, Math.min(gridSize - 1, c.x + dx));
          const newY = Math.max(0, Math.min(gridSize - 1, c.y + dy));
          return { ...c, x: newX, y: newY };
        }
        return c;
      })
    );
  };

  const attack = attackerId => {
    const attacker = characters.find(c => c.id === attackerId);
    if (!attacker) return;

    // Adjacent enemies
    const targets = characters.filter(
      c => c.team !== attacker.team && Math.abs(c.x - attacker.x) + Math.abs(c.y - attacker.y) === 1 && c.hp > 0
    );

    if (targets.length > 0) {
      const target = targets[0];
      setCharacters(prev =>
        prev.map(c =>
          c.id === target.id ? { ...c, hp: Math.max(0, c.hp - attacker.atk) } : c
        )
      );
    }
  };

  const endTurn = () => {
    setSelectedId(null);
    setTurn(prev => (prev === 'A' ? 'B' : 'A'));
  };

  // Filter alive characters for display
  const aliveCharacters = characters.filter(c => c.hp > 0);

  return (
    <div className="App" style={{ display: 'flex', gap: '20px', padding: '20px' }}>
      <div>
        <h1>DuelGrid</h1>
        <h2>Turn: Team {turn}</h2>
        <div className="grid">
          {Array.from({ length: gridSize }).map((_, y) => (
            <div key={y} className="row">
              {Array.from({ length: gridSize }).map((_, x) => {
                const char = aliveCharacters.find(c => c.x === x && c.y === y);
                return (
                  <div
                    key={x}
                    className={`tile ${char ? 'occupied' : ''} ${
                      selectedId === (char ? char.id : null) ? 'selected' : ''
                    }`}
                    onClick={() => {
                      if (char && char.team === turn) setSelectedId(char.id);
                    }}
                  >
                    {char && (
                      <div className="character">
                        <img src={char.sprite} alt={char.name} className="sprite" />
                        <div className="stats">
                          <div>{char.name}</div>
                          <div>HP: {char.hp}</div>
                          <div>ATK: {char.atk}</div>
                        </div>
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          ))}
        </div>
        <div className="controls">
          {selectedChar && selectedChar.team === turn && (
            <>
              <button onClick={() => moveCharacter(selectedId, -1, 0)}>←</button>
              <button onClick={() => moveCharacter(selectedId, 1, 0)}>→</button>
              <button onClick={() => moveCharacter(selectedId, 0, -1)}>↑</button>
              <button onClick={() => moveCharacter(selectedId, 0, 1)}>↓</button>
              <button onClick={() => attack(selectedId)}>Attack</button>
              <button onClick={endTurn}>End Turn</button>
            </>
          )}
        </div>
      </div>

      {/* Sidebar with Characters */}
      <div style={{ width: '280px', border: '1px solid #888', borderRadius: '8px', padding: '10px', background: '#222', color: '#eee', overflowY: 'auto', height: '600px' }}>
        <h3>Team A Characters</h3>
        {aliveCharacters.filter(c => c.team === 'A').map(c => (
          <div key={c.id} style={{ display: 'flex', alignItems: 'center', marginBottom: '10px', background: c.id === selectedId ? '#444' : 'transparent', padding: '5px', borderRadius: '5px', cursor: 'pointer' }}
            onClick={() => setSelectedId(c.id)}
          >
            <img src={c.sprite} alt={c.name} style={{ width: '40px', height: '40px', marginRight: '10px' }} />
            <div>
              <div><strong>{c.name}</strong></div>
              <div>HP: {c.hp}</div>
              <div>ATK: {c.atk}</div>
            </div>
          </div>
        ))}
        <h3>Team B Characters</h3>
        {aliveCharacters.filter(c => c.team === 'B').map(c => (
          <div key={c.id} style={{ display: 'flex', alignItems: 'center', marginBottom: '10px', background: c.id === selectedId ? '#444' : 'transparent', padding: '5px', borderRadius: '5px', cursor: 'pointer' }}
            onClick={() => setSelectedId(c.id)}
          >
            <img src={c.sprite} alt={c.name} style={{ width: '40px', height: '40px', marginRight: '10px' }} />
            <div>
              <div><strong>{c.name}</strong></div>
              <div>HP: {c.hp}</div>
              <div>ATK: {c.atk}</div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

export default App;
